import{c as a,Q as d,j as r,m as e}from"./chunks/framework.BIBjCrbN.js";const b=JSON.parse('{"title":"生物医学工程方向","description":"中国顶尖高校生物医学工程方向博士导师汇总，涵盖医疗器械、生物材料、康复工程等方向","frontmatter":{"title":"生物医学工程方向","description":"中国顶尖高校生物医学工程方向博士导师汇总，涵盖医疗器械、生物材料、康复工程等方向"},"headers":[],"relativePath":"research-directions/bme.md","filePath":"research-directions/bme.md","lastUpdated":1780110618000}'),h={name:"research-directions/bme.md"};function i(s,t,o,l,n,p){return d(),r("div",null,[...t[0]||(t[0]=[e('<h1 id="生物医学工程-bme" tabindex="-1">生物医学工程 (BME) <a class="header-anchor" href="#生物医学工程-bme" aria-label="Permalink to &quot;生物医学工程 (BME)&quot;">​</a></h1><h2 id="方向概述" tabindex="-1">方向概述 <a class="header-anchor" href="#方向概述" aria-label="Permalink to &quot;方向概述&quot;">​</a></h2><p>生物医学工程将工程学原理应用于医学和生命科学领域。国内BME方向在<strong>上海交通大学</strong>、<strong>华中科技大学</strong>、<strong>东南大学</strong>拥有国家一级重点学科，清华大学、浙江大学也在快速发展。</p><h2 id="子方向" tabindex="-1">子方向 <a class="header-anchor" href="#子方向" aria-label="Permalink to &quot;子方向&quot;">​</a></h2><ul><li><strong>医疗器械与系统</strong>：超声治疗、微创诊疗 — 清华(廖洪恩)、上交</li><li><strong>生物材料与组织工程</strong>：纳米材料、再生医学 — 川大(张兴栋院士)、清华(杜亚楠)</li><li><strong>生物力学</strong>：骨骼/心血管力学 — 北航</li><li><strong>康复工程</strong>：运动功能障碍康复 — 中科院(侯增广)</li><li><strong>生物传感器与微流控</strong>：生物芯片、纳米传感器 — 清华(程京院士、李舟)</li><li><strong>神经工程（BME视角）</strong>：神经假体、脑机接口硬件 — 清华(洪波)、浙大</li></ul><hr><h2 id="导师全索引" tabindex="-1">导师全索引 <a class="header-anchor" href="#导师全索引" aria-label="Permalink to &quot;导师全索引&quot;">​</a></h2><h3 id="清华大学-生物医学工程学院" tabindex="-1">清华大学（生物医学工程学院） <a class="header-anchor" href="#清华大学-生物医学工程学院" aria-label="Permalink to &quot;清华大学（生物医学工程学院）&quot;">​</a></h3><table tabindex="0"><thead><tr><th>导师</th><th>职称</th><th>核心方向</th><th>备注</th></tr></thead><tbody><tr><td>程京</td><td>教授、院士</td><td>生物芯片、精准医学</td><td>不招直博生</td></tr><tr><td>廖洪恩</td><td>教授</td><td>医学影像引导治疗、微创诊疗</td><td>—</td></tr><tr><td>杜亚楠</td><td>教授</td><td>生物材料、组织工程</td><td>—</td></tr><tr><td>郭华</td><td>教授</td><td>医学影像、MRI物理与工程</td><td>—</td></tr><tr><td>罗建文</td><td>教授</td><td>超声成像、弹性成像</td><td>—</td></tr><tr><td>戴小川</td><td>教授</td><td>神经工程、柔性电子</td><td>—</td></tr><tr><td>李舟</td><td>教授</td><td>纳米生物传感器</td><td>—</td></tr></tbody></table><p>详见 <a href="/apply-phd/universities/tsinghua">清华大学</a> 页面。</p><h3 id="上海交通大学" tabindex="-1">上海交通大学 <a class="header-anchor" href="#上海交通大学" aria-label="Permalink to &quot;上海交通大学&quot;">​</a></h3><p>上交BME学院在生物医疗仪器、纳米医学、医学影像方向师资力量强大。 详见 <a href="/apply-phd/universities/sjtu">上海交通大学</a> 页面。</p><h3 id="东南大学" tabindex="-1">东南大学 <a class="header-anchor" href="#东南大学" aria-label="Permalink to &quot;东南大学&quot;">​</a></h3><table tabindex="0"><thead><tr><th>导师</th><th>职称</th><th>核心方向</th><th>备注</th></tr></thead><tbody><tr><td><a href="/apply-phd/universities/seu">顾忠泽</a></td><td>首席教授、长江学者</td><td>器官芯片、类脑器官、生物电子学</td><td>数字医学工程国重实验室主任</td></tr></tbody></table><p>BME国家一级重点学科，生物电子学、器官芯片为特色。 详见 <a href="/apply-phd/universities/seu">东南大学</a> 页面。</p><h3 id="华中科技大学" tabindex="-1">华中科技大学 <a class="header-anchor" href="#华中科技大学" aria-label="Permalink to &quot;华中科技大学&quot;">​</a></h3><table tabindex="0"><thead><tr><th>导师</th><th>职称</th><th>核心方向</th><th>备注</th></tr></thead><tbody><tr><td><a href="/apply-phd/universities/hust">丁明跃</a></td><td>教授</td><td>超声断层成像（国内首个注册证）</td><td>IEEE高级会员</td></tr><tr><td><a href="/apply-phd/universities/hust">尉迟明</a></td><td>教授</td><td>超声CT系统研发</td><td>万人计划领军人才</td></tr><tr><td><a href="/apply-phd/universities/hust">邱武</a></td><td>教授</td><td>AI医学影像分析</td><td>国家高层次青年人才</td></tr></tbody></table><p>超声成像/PET/MRI方向突出，武汉光电国家研究中心提供光学成像平台。 详见 <a href="/apply-phd/universities/hust">华中科技大学</a> 页面。</p><h3 id="中山大学-深圳校区" tabindex="-1">中山大学（深圳校区） <a class="header-anchor" href="#中山大学-深圳校区" aria-label="Permalink to &quot;中山大学（深圳校区）&quot;">​</a></h3><table tabindex="0"><thead><tr><th>导师</th><th>职称</th><th>核心方向</th><th>备注</th></tr></thead><tbody><tr><td><a href="/apply-phd/universities/sysu">张贺晔</a></td><td>教授、国家杰青</td><td>医学影像AI、心血管无创诊断</td><td>2026名额较多</td></tr><tr><td><a href="/apply-phd/universities/sysu">曹众</a></td><td>教授</td><td>分子影像探针、纳米诊疗</td><td>深圳校区</td></tr><tr><td><a href="/apply-phd/universities/sysu">周建华</a></td><td>教授</td><td>生物传感、微流控</td><td>—</td></tr></tbody></table><p>软科世界一流学科排名全球第5，深圳地理位置与你现居地一致。 详见 <a href="/apply-phd/universities/sysu">中山大学</a> 页面。</p><h3 id="四川大学" tabindex="-1">四川大学 <a class="header-anchor" href="#四川大学" aria-label="Permalink to &quot;四川大学&quot;">​</a></h3><p>张兴栋院士领衔的生物材料方向全国领先。 详见 <a href="/apply-phd/universities/scu">四川大学</a> 页面。</p><h3 id="其他院校" tabindex="-1">其他院校 <a class="header-anchor" href="#其他院校" aria-label="Permalink to &quot;其他院校&quot;">​</a></h3><p>北京航空航天大学、西安交通大学等均有BME博士点。 详见各校页面。</p><hr><h2 id="针对你的申请建议" tabindex="-1">针对你的申请建议 <a class="header-anchor" href="#针对你的申请建议" aria-label="Permalink to &quot;针对你的申请建议&quot;">​</a></h2><p>BME方向对你而言是<strong>最宽口径</strong>的选择：</p><ul><li><strong>生物医疗仪器方向</strong>最匹配你的背景（超声RA经验 + EMG硬件开发）</li><li><strong>神经工程</strong>在BME语境下更偏硬件/设备，适合你的工程能力</li><li><strong>生物材料/组织工程</strong>方向需要更多化学/材料学背景，匹配度较低</li></ul><p>建议申请BME项目时，在你的研究计划中重点突出<strong>工程实践能力</strong>（电路设计、系统集成、原型开发），这是许多纯生物/医学背景申请人不具备的差异化优势。</p>',30)])])}const c=a(h,[["render",i]]);export{b as __pageData,c as default};
